@strawberry.type
class Product:
    id: strawberry.ID
    sku: str
    name: str
    description: Optional[str]
    price: float

    @strawberry.field
    def seller(self, info: Info) -> Optional[Seller]:
        m: ProductModel = info.context["product_model"]
        if m.seller is None:
            return None
        return Seller(id=str(m.seller.id), name=m.seller.name, rating=m.seller.rating)

    @strawberry.field
    def categories(self, info: Info) -> List[Category]:
        m: ProductModel = info.context["product_model"]
        return [Category(id=str(c.id), name=c.name) for c in (m.categories or [])]

    @strawberry.field
    def reviews(self, info: Info) -> List[Review]:
        m: ProductModel = info.context["product_model"]
        return [
            Review(
                id=str(r.id),
                author=r.author,
                rating=r.rating,
                body=r.body,
                created_at=r.created_at,
            )
            for r in (m.reviews or [])
        ]

    @strawberry.field
    def images(self, info: Info) -> List[Image]:
        m: ProductModel = info.context["product_model"]
        imgs = sorted((m.images or []), key=lambda x: (x.sort_order, x.id))
        return [
            Image(
                id=str(i.id),
                url=i.url,
                alt_text=i.alt_text,
                sort_order=i.sort_order,
            )
            for i in imgs
        ]


@strawberry.input
class ProductFilterInput:
    search: Optional[str] = None
    seller_id: Optional[strawberry.ID] = None
    category_id: Optional[strawberry.ID] = None
    min_price: Optional[float] = None
    max_price: Optional[float] = None


@strawberry.input
class ProductSortInput:
    field: str = "id"   # id | name | price | sku
    direction: str = "asc"  # asc | desc


def _apply_filters(stmt, f: Optional[ProductFilterInput]):
    if not f:
        return stmt
    if f.search:
        like = f"%{f.search}%"
        stmt = stmt.where((ProductModel.name.ilike(like)) | (ProductModel.description.ilike(like)) | (ProductModel.sku.ilike(like)))
    if f.seller_id:
        stmt = stmt.where(ProductModel.seller_id == int(str(f.seller_id)))
    if f.category_id:
        cid = int(str(f.category_id))
        stmt = stmt.join(product_categories, product_categories.c.product_id == ProductModel.id).where(product_categories.c.category_id == cid)
    if f.min_price is not None:
        stmt = stmt.where(ProductModel.price >= f.min_price)
    if f.max_price is not None:
        stmt = stmt.where(ProductModel.price <= f.max_price)
    return stmt


def _apply_sort(stmt, s: Optional[ProductSortInput]):
    if not s:
        return stmt.order_by(ProductModel.id.asc())
    field = (s.field or "id").lower()
    direction = (s.direction or "asc").lower()
    col = {
        "id": ProductModel.id,
        "name": ProductModel.name,
        "price": ProductModel.price,
        "sku": ProductModel.sku,
    }.get(field, ProductModel.id)
    if direction == "desc":
        return stmt.order_by(col.desc())
    return stmt.order_by(col.asc())


async def _get_products(
    session: AsyncSession,
    ids: Optional[Sequence[int]] = None,
    filter_: Optional[ProductFilterInput] = None,
    sort: Optional[ProductSortInput] = None,
) -> List[ProductModel]:
    stmt = select(ProductModel).options(
        selectinload(ProductModel.seller),
        selectinload(ProductModel.categories),
        selectinload(ProductModel.reviews),
        selectinload(ProductModel.images),
    )
    if ids is not None:
        stmt = stmt.where(ProductModel.id.in_(list(ids)))
    stmt = _apply_filters(stmt, filter_)
    stmt = _apply_sort(stmt, sort)
    res = await session.execute(stmt)
    return list(res.scalars().unique().all())


