@strawberry.type
class Query:
    @strawberry.field
    async def product(self, info: Info, id: strawberry.ID) -> Optional[Product]:
        async with SessionLocal() as session:
            products = await _get_products(session, ids=[int(str(id))])
            if not products:
                return None
            m = products[0]
            info.context["product_model"] = m
            return Product(
                id=str(m.id),
                sku=m.sku,
                name=m.name,
                description=m.description,
                price=m.price,
            )

    @strawberry.field
    async def products(
        self,
        info: Info,
        filter: Optional[ProductFilterInput] = None,
        sort: Optional[ProductSortInput] = None,
    ) -> List[Product]:
        async with SessionLocal() as session:
            ms = await _get_products(session, filter_=filter, sort=sort)
            out: List[Product] = []
            for m in ms:
                info.context["product_model"] = m
                out.append(
                    Product(
                        id=str(m.id),
                        sku=m.sku,
                        name=m.name,
                        description=m.description,
                        price=m.price,
                    )
                )
            return out

    @strawberry.field
    async def categories(self, info: Info) -> List[Category]:
        async with SessionLocal() as session:
            res = await session.execute(select(CategoryModel).order_by(CategoryModel.name.asc()))
            return [Category(id=str(c.id), name=c.name) for c in res.scalars().all()]

    @strawberry.field
    async def sellers(self, info: Info) -> List[Seller]:
        async with SessionLocal() as session:
            res = await session.execute(select(SellerModel).order_by(SellerModel.name.asc()))
            return [Seller(id=str(s.id), name=s.name, rating=s.rating) for s in res.scalars().all()]


schema = strawberry.Schema(query=Query)


